async (params, browser) => {
  // Open Telegram Web
  await browser.open('https://web.telegram.org/k/')

  // Wait for Telegram to load
  await browser.waitForSelector('.input-search input, .chatlist-chat, .chat-list', 15000)

  // Let app fully initialize
  await browser.wait(2000)

  // Search for the chat
  const search_chat = await browser.evaluate(`const searchInput = document.querySelector('.input-search input') || document.querySelector('input[type="text"]'); if (searchInput) { searchInput.focus(); searchInput.click(); await new Promise(r => setTimeout(r, 300)); searchInput.value = ''; searchInput.dispatchEvent(new Event('input', { bubbles: true })); document.execCommand('insertText', false, params.chat_name); searchInput.dispatchEvent(new Event('input', { bubbles: true })); } return { searched: true }`)

  // Wait for search results
  await browser.wait(2500)

  // Click on the matching chat
  const click_chat = await browser.evaluate(`const chatItems = document.querySelectorAll('.chatlist-chat, .chat-list .ListItem, .search-group .chatlist-chat'); let clicked = false; for (const item of chatItems) { const nameEl = item.querySelector('.peer-title, .user-title, .dialog-title'); if (nameEl && nameEl.textContent.trim().toLowerCase().includes(params.chat_name.toLowerCase())) { item.click(); clicked = true; break; } } if (!clicked && chatItems.length > 0) { chatItems[0].click(); clicked = true; } return { clicked: clicked }`)

  // Wait for messages to load
  await browser.wait(3000)

  // Wait for message bubbles
  await browser.waitForSelector('.bubble, .message, .bubble-content', 10000)

  // Scroll up to load more messages
  const scroll_up = await browser.evaluate(`const targetCount = parseInt(params.message_count || '50', 10); const scrollContainer = document.querySelector('.bubbles-inner, .scrollable-y, .bubbles .scrollable'); const scrollAttempts = Math.ceil(targetCount / 15); for (let i = 0; i < scrollAttempts; i++) { if (scrollContainer) { scrollContainer.scrollTop = 0; } else { const bubblesEl = document.querySelector('.bubbles'); if (bubblesEl) bubblesEl.scrollTop = 0; } await new Promise(r => setTimeout(r, 1500)); } return { scroll_attempts: scrollAttempts, target: targetCount }`)

  // Wait for scrolled messages to render
  await browser.wait(2000)

  // Export all visible messages
  const export_result = await browser.evaluate(`const targetCount = parseInt(params.message_count || '50', 10); const messages = []; const bubbles = document.querySelectorAll('.bubble:not(.is-date), .message'); const startIdx = Math.max(0, bubbles.length - targetCount); for (let i = startIdx; i < bubbles.length; i++) { const el = bubbles[i]; const authorEl = el.querySelector('.peer-title, .name, .bubble-name .peer-title'); const contentEl = el.querySelector('.text-content, .message-content, .message'); const timeEl = el.querySelector('.time, time, .bubble-content .time'); const content = contentEl ? contentEl.textContent.trim() : ''; if (!content) continue; const isOutgoing = el.classList.contains('is-out') || el.classList.contains('outgoing'); const replyEl = el.querySelector('.reply, .reply-title'); messages.push({ index: messages.length + 1, author: authorEl ? authorEl.textContent.trim() : '', content: content, timestamp: timeEl ? timeEl.textContent.trim() : '', direction: isOutgoing ? 'outgoing' : 'incoming', has_reply: replyEl ? true : false, reply_to: replyEl ? replyEl.textContent.trim() : '' }); } const chatTitle = document.querySelector('.chat-info .peer-title, .top .peer-title'); return { chat_name: chatTitle ? chatTitle.textContent.trim() : params.chat_name, total_exported: messages.length, target_count: targetCount, messages: messages }`)

  return export_result
}
